mapper.select:
SELECT
    b.*,
    m.display_name AS embedding_model
FROM kb_base b
LEFT JOIN llm_model m ON b.embedding_model_id = m.id AND m.del_flag = 0
WHERE b.del_flag = '0'

    AND b.kb_id = #{bo.kbId}


    AND b.tenant_id = #{bo.tenantId}


    AND b.kb_code LIKE CONCAT('%', #{bo.kbCode}, '%')


    AND b.kb_name LIKE CONCAT('%', #{bo.kbName}, '%')


    AND b.description LIKE CONCAT('%', #{bo.description}, '%')


    AND b.visibility = #{bo.visibility}


    AND b.owner_id = #{bo.ownerId}


    AND b.embedding_model_id = #{bo.embeddingModelId}


    AND m.display_name LIKE CONCAT('%', #{bo.embeddingModel}, '%')


    AND b.chunk_strategy = #{bo.chunkStrategy}


    AND b.chunk_size = #{bo.chunkSize}


    AND b.chunk_overlap = #{bo.chunkOverlap}


    AND b.status = #{bo.status}


    AND b.create_by = #{bo.createBy}


    AND b.create_time = #{bo.createTime}


    AND b.update_by = #{bo.updateBy}


    AND b.update_time = #{bo.updateTime}
